const SUPABASE_URL   = 'https://inhyrrjidhzrbqecnptn.supabase.co';
const SERVICE_KEY    = $env.N8N_SUPABASE_SERVICE_KEY;
const CHATWOOT_URL   = 'https://chat.redsolucionesti.com';
const CHATWOOT_TOKEN = 'yypAwZDH2dV3crfbqJqWCgj1';

const hdrs = { 'apikey': SERVICE_KEY, 'Authorization': 'Bearer ' + SERVICE_KEY };

// 1. Get all active clinics
const clinics = await this.helpers.httpRequest({
    method: 'GET',
    url: SUPABASE_URL + '/rest/v1/clinics?select=id,name,chatwoot_account_id&deleted_at=is.null',
    headers: hdrs, json: true
});

if (!Array.isArray(clinics) || clinics.length === 0) {
    return [{ json: { processed: 0, message: 'No active clinics' } }];
}

let totalSent = 0;
const results = [];

for (const clinic of clinics) {
    const accountId = clinic.chatwoot_account_id || 2;

    // 2. Get patients whose recall date has passed
    let patients = [];
    try {
        patients = await this.helpers.httpRequest({
            method: 'POST',
            url: SUPABASE_URL + '/rest/v1/rpc/get_patients_for_recall',
            headers: { ...hdrs, 'Content-Type': 'application/json' },
            body: { p_clinic_id: clinic.id },
            json: true
        });
    } catch (e) { patients = []; }

    if (!Array.isArray(patients) || patients.length === 0) continue;

    for (const patient of patients) {
        // 3. Find most recent Chatwoot conversation_id via appointments table
        let convId = null;
        try {
            const convData = await this.helpers.httpRequest({
                method: 'GET',
                url: SUPABASE_URL + '/rest/v1/appointments?select=conversation_id&patient_id=eq.' + patient.id
                    + '&clinic_id=eq.' + clinic.id
                    + '&conversation_id=not.is.null'
                    + '&order=created_at.desc&limit=1',
                headers: hdrs, json: true
            });
            if (Array.isArray(convData) && convData.length > 0) {
                convId = convData[0].conversation_id;
            }
        } catch (e) { /* skip */ }

        if (!convId) continue;

        const firstName    = (patient.full_name || 'paciente').split(' ')[0];
        const intervalText = patient.recall_interval_months >= 12
            ? (patient.recall_interval_months / 12) + ' año(s)'
            : patient.recall_interval_months + ' meses';

        const msg = [
            'Hola *' + firstName + '* 👋',
            '',
            'Han pasado *' + intervalText + '* desde tu última visita a *' + clinic.name + '*.',
            '',
            'Es el momento de tu *chequeo de rutina* para mantener tu salud en óptimas condiciones. 🦷✨',
            '',
            '¿Te gustaría agendar una cita? Solo responde *SÍ* y te ayudo a encontrar el mejor horario.',
            '',
            '_SofIA · ' + clinic.name + '_'
        ].join('\n');

        // 4. Send recall message via Chatwoot
        try {
            await this.helpers.httpRequest({
                method: 'POST',
                url: CHATWOOT_URL + '/api/v1/accounts/' + accountId + '/conversations/' + convId + '/messages',
                headers: { 'api_access_token': CHATWOOT_TOKEN, 'Content-Type': 'application/json' },
                body: { content: msg, message_type: 'outgoing', private: false },
                json: true
            });
        } catch (e) {
            results.push({ patient_id: patient.id, error: String(e.message) });
            continue;
        }

        // 5. Update last_recall_sent_at
        try {
            await this.helpers.httpRequest({
                method: 'PATCH',
                url: SUPABASE_URL + '/rest/v1/patients?id=eq.' + patient.id,
                headers: { ...hdrs, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
                body: { last_recall_sent_at: new Date().toISOString() },
                json: true
            });
        } catch (e) { /* non-critical */ }

        totalSent++;
        results.push({ patient_id: patient.id, name: patient.full_name, clinic: clinic.name, sent: true });
    }
}

return [{ json: { processed: totalSent, results } }];
